  1→//! WebSocket client that connects to a gateway as a headless node.
  2→
  3→use std::{process::Stdio, time::Duration};
  4→
  5→use {
  6→    futures::{SinkExt, StreamExt},
  7→    tokio::process::Command,
  8→    tokio_tungstenite::{connect_async, tungstenite::Message},
  9→    tracing::{debug, error, info, warn},
 10→};
 11→
 12→use moltis_protocol::{
 13→    ClientInfo, ConnectAuth, ConnectParamsV4, GatewayFrame, PROTOCOL_VERSION, ProtocolRange,
 14→    RequestFrame, ResponseFrame, roles,
 15→};
 16→
 17→/// Configuration for connecting a node to a gateway.
 18→#[derive(Debug, Clone)]
 19→pub struct NodeConfig {
 20→    /// Gateway WebSocket URL (e.g. `ws://localhost:9090/ws`).
 21→    pub gateway_url: String,
 22→    /// Device token obtained from the pairing flow.
 23→    pub device_token: String,
 24→    /// Unique node identifier.
 25→    pub node_id: String,
 26→    /// Human-readable display name.
 27→    pub display_name: Option<String>,
 28→    /// Platform string (e.g. "macos", "linux").
 29→    pub platform: String,
 30→    /// Capabilities this node advertises (e.g. "system.run").
 31→    pub caps: Vec<String>,
 32→    /// Commands this node supports (e.g. "system.run", "system.which").
 33→    pub commands: Vec<String>,
 34→    /// Maximum time for a single command execution.
 35→    pub exec_timeout: Duration,
 36→    /// Working directory for commands (defaults to $HOME).
 37→    pub working_dir: Option<String>,
 38→}
 39→
 40→impl Default for NodeConfig {
 41→    fn default() -> Self {
 42→        Self {
 43→            gateway_url: "ws://localhost:9090/ws".into(),
 44→            device_token: String::new(),
 45→            node_id: uuid::Uuid::new_v4().to_string(),
 46→            display_name: None,
 47→            platform: std::env::consts::OS.into(),
 48→            caps: vec![
 49→                "system.run".into(),
 50→                "system.which".into(),
 51→                "system.providers".into(),
 52→            ],
 53→            commands: vec![
 54→                "system.run".into(),
 55→                "system.which".into(),
 56→                "system.providers".into(),
 57→            ],
 58→            exec_timeout: Duration::from_secs(300),
 59→            working_dir: None,
 60→        }
 61→    }
 62→}
 63→
 64→/// Detect installed runtimes using `which`.
 65→fn detect_runtimes() -> Vec<String> {
 66→    let candidates = ["python3", "python", "node", "ruby", "go", "rustc", "java"];
 67→    let mut found = Vec::new();
 68→    for name in candidates {
 69→        // Skip "python" if we already found "python3".
 70→        if name == "python" && found.contains(&"python3".to_string()) {
 71→            continue;
 72→        }
 73→        if which::which(name).is_ok() {
 74→            found.push(name.to_string());
 75→        }
 76→    }
 77→    found
 78→}
