 80→/// Collect system telemetry using `sysinfo`.
 81→fn collect_system_telemetry(node_id: &str) -> serde_json::Value {
 82→    use sysinfo::{Disks, System};
 83→
 84→    let mut sys = System::new();
 85→    sys.refresh_memory();
 86→    sys.refresh_cpu_all();
 87→
 88→    let uptime = System::uptime();
 89→
 90→    // Disk: find the root partition.
 91→    let disks = Disks::new_with_refreshed_list();
 92→    let root_disk = disks
 93→        .iter()
 94→        .find(|d| d.mount_point() == std::path::Path::new("/"));
 95→    let disk_total = root_disk.map(|d| d.total_space());
 96→    let disk_available = root_disk.map(|d| d.available_space());
 97→
 98→    let runtimes = detect_runtimes();
 99→
100→    serde_json::json!({
101→        "nodeId": node_id,
102→        "mem": {
103→            "total": sys.total_memory(),
104→            "available": sys.available_memory(),
105→        },
106→        "cpuCount": sys.cpus().len(),
107→        "cpuUsage": sys.global_cpu_usage(),
108→        "uptime": uptime,
109→        "services": [],
110→        "disk": {
111→            "total": disk_total,
112→            "available": disk_available,
113→        },
114→        "runtimes": runtimes,
115→    })
116→}
