118→/// A headless node host that connects to a gateway and handles commands.
119→pub struct NodeHost {
120→    config: NodeConfig,
121→}
122→
123→impl NodeHost {
124→    pub fn new(config: NodeConfig) -> Self {
125→        Self { config }
126→    }
127→
128→    /// Connect to the gateway and run the message loop until disconnected.
129→    ///
130→    /// Returns `Ok(())` on clean shutdown, `Err` on connection/protocol errors.
131→    pub async fn run(&self) -> anyhow::Result<()> {
132→        // Validate URL first, then pass string to connect_async.
133→        let _url = url::Url::parse(&self.config.gateway_url)?;
134→        info!(url = %self.config.gateway_url, node_id = %self.config.node_id, "connecting to gateway");
135→
136→        let (ws_stream, _response) = connect_async(&self.config.gateway_url).await?;
137→        let (mut ws_tx, mut ws_rx) = ws_stream.split();
138→
139→        info!("websocket connected, sending handshake");
140→
141→        // Build and send connect request (v4 format).
142→        let connect_id = uuid::Uuid::new_v4().to_string();
143→        let connect_params = ConnectParamsV4 {
144→            protocol: ProtocolRange {
145→                min: PROTOCOL_VERSION,
146→                max: PROTOCOL_VERSION,
147→            },
148→            client: ClientInfo {
149→                id: self.config.node_id.clone(),
150→                display_name: self.config.display_name.clone(),
151→                version: moltis_config::VERSION.into(),
152→                platform: self.config.platform.clone(),
153→                device_family: None,
154→                model_identifier: None,
155→                mode: "headless".into(),
156→                instance_id: None,
157→            },
158→            role: Some(roles::NODE.into()),
159→            scopes: None,
160→            auth: Some(ConnectAuth {
161→                token: None,
162→                password: None,
163→                api_key: None,
164→                device_token: Some(self.config.device_token.clone()),
165→            }),
166→            locale: None,
167→            timezone: None,
168→            extensions: {
169→                let mut ext = std::collections::HashMap::new();
170→                ext.insert(
171→                    "moltis".into(),
172→                    serde_json::json!({
173→                        "caps": self.config.caps,
174→                        "commands": self.config.commands,
175→                    }),
176→                );
177→                ext
178→            },
179→        };
180→
181→        let connect_req = RequestFrame {
182→            r#type: "req".into(),
183→            id: connect_id.clone(),
184→            method: "connect".into(),
185→            params: Some(serde_json::to_value(&connect_params)?),
186→            channel: None,
187→        };
188→
189→        let connect_json = serde_json::to_string(&connect_req)?;
190→        ws_tx.send(Message::Text(connect_json.into())).await?;
191→
192→        // Wait for hello-ok response.
193→        let hello = match tokio::time::timeout(Duration::from_secs(10), ws_rx.next()).await {
194→            Ok(Some(Ok(Message::Text(text)))) => {
195→                let resp: ResponseFrame = serde_json::from_str(&text)?;
196→                if resp.id != connect_id {
197→                    anyhow::bail!(
198→                        "unexpected response id: expected {connect_id}, got {}",
199→                        resp.id
200→                    );
201→                }
202→                if !resp.ok {
203→                    let err_msg = resp
204→                        .error
205→                        .map(|e| format!("{}: {}", e.code, e.message))
206→                        .unwrap_or_else(|| "unknown error".into());
207→                    anyhow::bail!("handshake failed: {err_msg}");
208→                }
209→                resp
210→            },
211→            Ok(Some(Ok(_))) => anyhow::bail!("unexpected non-text message during handshake"),
212→            Ok(Some(Err(e))) => anyhow::bail!("websocket error during handshake: {e}"),
213→            Ok(None) => anyhow::bail!("connection closed during handshake"),
214→            Err(_) => anyhow::bail!("handshake timeout"),
215→        };
216→
217→        info!(
218→            server_version = hello
219→                .payload
220→                .as_ref()
221→                .and_then(|p| p.get("server"))
222→                .and_then(|s| s.get("version"))
223→                .and_then(|v| v.as_str())
224→                .unwrap_or("unknown"),
225→            "handshake complete, node registered"
226→        );
227→
228→        // Main message loop with telemetry ticker.
229→        let mut telemetry_interval = tokio::time::interval(Duration::from_secs(30));
230→        // Skip the immediate first tick — send telemetry after the first interval.
231→        telemetry_interval.tick().await;
232→
233→        loop {
234→            tokio::select! {
235→                msg = ws_rx.next() => {
236→                    match msg {
237→                        Some(Ok(Message::Text(text))) => {
238→                            self.handle_message(&text, &mut ws_tx).await;
239→                        },
240→                        Some(Ok(Message::Ping(data))) => {
241→                            if let Err(e) = ws_tx.send(Message::Pong(data)).await {
242→                                warn!(error = %e, "failed to send pong");
243→                                break;
244→                            }
245→                        },
246→                        Some(Ok(Message::Close(_))) => {
247→                            info!("gateway closed connection");
248→                            break;
249→                        },
250→                        Some(Ok(_)) => {},
251→                        Some(Err(e)) => {
252→                            error!(error = %e, "websocket error");
253→                            break;
254→                        },
255→                        None => {
256→                            info!("websocket stream ended");
257→                            break;
258→                        },
259→                    }
260→                },
261→                _ = telemetry_interval.tick() => {
262→                    self.send_telemetry(&mut ws_tx).await;
263→                },
264→            }
265→        }
266→
267→        info!("node disconnected");
268→        Ok(())
269→    }
270→
271→    async fn handle_message(
272→        &self,
273→        text: &str,
274→        ws_tx: &mut (impl SinkExt<Message, Error = tokio_tungstenite::tungstenite::Error> + Unpin),
275→    ) {
276→        // Try to parse as a GatewayFrame to determine the type.
277→        let frame: GatewayFrame = match serde_json::from_str(text) {
278→            Ok(f) => f,
279→            Err(e) => {
280→                debug!(error = %e, "failed to parse frame, ignoring");
281→                return;
282→            },
283→        };
284→
285→        match frame {
286→            GatewayFrame::Event(event) => {
287→                if event.event == "node.invoke.request" {
288→                    self.handle_invoke(event.payload, ws_tx).await;
289→                } else {
290→                    debug!(event = %event.event, "ignoring event");
291→                }
292→            },
293→            GatewayFrame::Request(req) => {
294→                debug!(method = %req.method, id = %req.id, "ignoring server request");
295→            },
296→            GatewayFrame::Response(_) => {
297→                debug!("ignoring response frame");
298→            },
299→        }
300→    }
301→
302→    async fn handle_invoke(
303→        &self,
304→        payload: Option<serde_json::Value>,
305→        ws_tx: &mut (impl SinkExt<Message, Error = tokio_tungstenite::tungstenite::Error> + Unpin),
306→    ) {
307→        let payload = match payload {
308→            Some(p) => p,
309→            None => return,
310→        };
311→
312→        let invoke_id = match payload.get("invokeId").and_then(|v| v.as_str()) {
313→            Some(id) => id.to_string(),
314→            None => {
315→                warn!("invoke request missing invokeId");
316→                return;
317→            },
318→        };
319→
320→        let command = match payload.get("command").and_then(|v| v.as_str()) {
321→            Some(c) => c,
322→            None => {
323→                warn!(invoke_id = %invoke_id, "invoke request missing command");
324→                self.send_invoke_error(&invoke_id, "missing command", ws_tx)
325→                    .await;
326→                return;
327→            },
328→        };
329→
330→        let args = payload.get("args").cloned().unwrap_or_default();
331→
332→        info!(invoke_id = %invoke_id, command = %command, "handling invoke");
333→
334→        let result = match command {
335→            "system.run" => self.handle_system_run(&args).await,
336→            "system.which" => self.handle_system_which(&args).await,
337→            "system.providers" => self.handle_system_providers().await,
338→            other => {
339→                warn!(command = %other, "unsupported invoke command");
340→                Err(anyhow::anyhow!("unsupported command: {other}"))
341→            },
342→        };
343→
344→        match result {
345→            Ok(value) => {
346→                self.send_invoke_result(&invoke_id, value, ws_tx).await;
347→            },
348→            Err(e) => {
349→                self.send_invoke_error(&invoke_id, &e.to_string(), ws_tx)
350→                    .await;
351→            },
352→        }
353→    }
354→
355→    async fn handle_system_run(
356→        &self,
357→        args: &serde_json::Value,
358→    ) -> anyhow::Result<serde_json::Value> {
359→        let command = args
360→            .get("command")
361→            .and_then(|v| v.as_str())
362→            .ok_or_else(|| anyhow::anyhow!("missing 'command' in args"))?;
363→
364→        let timeout_ms = args
365→            .get("timeout")
366→            .and_then(|v| v.as_u64())
367→            .unwrap_or(self.config.exec_timeout.as_millis() as u64);
368→        let timeout = Duration::from_millis(timeout_ms);
369→
370→        let cwd = args
371→            .get("cwd")
372→            .and_then(|v| v.as_str())
373→            .map(String::from)
374→            .or_else(|| self.config.working_dir.clone());
375→
376→        info!(command = %command, timeout_ms, "system.run");
377→
378→        let mut cmd = Command::new("sh");
379→        cmd.arg("-c").arg(command);
380→        cmd.stdout(Stdio::piped());
381→        cmd.stderr(Stdio::piped());
382→        cmd.stdin(Stdio::null());
383→
384→        if let Some(ref dir) = cwd {
385→            cmd.current_dir(dir);
386→        }
387→
388→        // Apply environment from args if provided.
389→        if let Some(env_obj) = args.get("env").and_then(|v| v.as_object()) {
390→            for (k, v) in env_obj {
391→                if let Some(val) = v.as_str() {
392→                    cmd.env(k, val);
393→                }
394→            }
395→        }
396→
397→        let child = cmd.spawn()?;
398→        let result = tokio::time::timeout(timeout, child.wait_with_output()).await;
399→
400→        match result {
401→            Ok(Ok(output)) => {
402→                let stdout = String::from_utf8_lossy(&output.stdout).into_owned();
403→                let stderr = String::from_utf8_lossy(&output.stderr).into_owned();
404→                let exit_code = output.status.code().unwrap_or(-1);
405→
406→                Ok(serde_json::json!({
407→                    "stdout": stdout,
408→                    "stderr": stderr,
409→                    "exitCode": exit_code,
410→                }))
411→            },
412→            Ok(Err(e)) => Err(anyhow::anyhow!("failed to execute command: {e}")),
413→            Err(_) => Err(anyhow::anyhow!("command timed out after {timeout_ms}ms")),
414→        }
415→    }
416→
417→    async fn handle_system_which(
418→        &self,
419→        args: &serde_json::Value,
420→    ) -> anyhow::Result<serde_json::Value> {
421→        let binary = args
422→            .get("binary")
423→            .and_then(|v| v.as_str())
424→            .ok_or_else(|| anyhow::anyhow!("missing 'binary' in args"))?;
425→
426→        let output = Command::new("which").arg(binary).output().await?;
427→
428→        let path = String::from_utf8_lossy(&output.stdout).trim().to_string();
429→        let found = output.status.success();
430→
431→        Ok(serde_json::json!({
432→            "found": found,
433→            "path": if found { Some(path) } else { None },
434→        }))
435→    }
436→
437→    async fn handle_system_providers(&self) -> anyhow::Result<serde_json::Value> {
438→        let mut providers = Vec::new();
439→
440→        // Check Ollama at localhost:11434.
441→        if let Ok(resp) = reqwest::Client::new()
442→            .get("http://localhost:11434/api/tags")
443→            .timeout(Duration::from_secs(3))
444→            .send()
445→            .await
446→            && resp.status().is_success()
447→            && let Ok(body) = resp.json::<serde_json::Value>().await
448→        {
449→            let models: Vec<String> = body
450→                .get("models")
451→                .and_then(|v| v.as_array())
452→                .map(|arr| {
453→                    arr.iter()
454→                        .filter_map(|m| m.get("name").and_then(|n| n.as_str()).map(String::from))
455→                        .collect()
456→                })
457→                .unwrap_or_default();
458→            providers.push(serde_json::json!({
459→                "provider": "ollama",
460→                "models": models,
461→            }));
462→        }
463→
464→        // Check for known API key env vars (presence only, never the values).
465→        let api_key_checks = [
466→            ("OPENAI_API_KEY", "openai"),
467→            ("ANTHROPIC_API_KEY", "anthropic"),
468→            ("GOOGLE_API_KEY", "google"),
469→            ("MISTRAL_API_KEY", "mistral"),
470→            ("GROQ_API_KEY", "groq"),
471→            ("TOGETHER_API_KEY", "together"),
472→        ];
473→        for (env_var, provider_name) in api_key_checks {
474→            if std::env::var(env_var).is_ok_and(|v| !v.is_empty()) {
475→                providers.push(serde_json::json!({
476→                    "provider": provider_name,
477→                    "models": [],
478→                }));
479→            }
480→        }
481→
482→        Ok(serde_json::json!({ "providers": providers }))
483→    }
484→
485→    async fn send_invoke_result(
486→        &self,
487→        invoke_id: &str,
488→        result: serde_json::Value,
489→        ws_tx: &mut (impl SinkExt<Message, Error = tokio_tungstenite::tungstenite::Error> + Unpin),
490→    ) {
491→        let frame = serde_json::json!({
492→            "type": "req",
493→            "id": uuid::Uuid::new_v4().to_string(),
494→            "method": "node.invoke.result",
495→            "params": {
496→                "invokeId": invoke_id,
497→                "result": result,
498→            }
499→        });
500→
501→        if let Ok(json) = serde_json::to_string(&frame)
502→            && let Err(e) = ws_tx.send(Message::Text(json.into())).await
503→        {
504→            warn!(invoke_id = %invoke_id, error = %e, "failed to send invoke result");
505→        }
506→    }
507→
508→    async fn send_telemetry(
509→        &self,
510→        ws_tx: &mut (impl SinkExt<Message, Error = tokio_tungstenite::tungstenite::Error> + Unpin),
511→    ) {
512→        let telemetry = collect_system_telemetry(&self.config.node_id);
513→        let frame = serde_json::json!({
514→            "type": "req",
515→            "id": uuid::Uuid::new_v4().to_string(),
516→            "method": "node.event",
517→            "params": {
518→                "event": "node.telemetry",
519→                "payload": telemetry,
520→            }
521→        });
522→
523→        if let Ok(json) = serde_json::to_string(&frame)
524→            && let Err(e) = ws_tx.send(Message::Text(json.into())).await
525→        {
526→            debug!(error = %e, "failed to send telemetry");
527→        }
528→    }
529→
530→    async fn send_invoke_error(
531→        &self,
532→        invoke_id: &str,
533→        error: &str,
534→        ws_tx: &mut (impl SinkExt<Message, Error = tokio_tungstenite::tungstenite::Error> + Unpin),
535→    ) {
536→        let frame = serde_json::json!({
537→            "type": "req",
538→            "id": uuid::Uuid::new_v4().to_string(),
539→            "method": "node.invoke.result",
540→            "params": {
541→                "invokeId": invoke_id,
542→                "result": { "error": error },
543→            }
544→        });
545→
546→        if let Ok(json) = serde_json::to_string(&frame)
547→            && let Err(e) = ws_tx.send(Message::Text(json.into())).await
548→        {
549→            warn!(invoke_id = %invoke_id, error = %e, "failed to send invoke error");
550→        }
551→    }
552→}
