554→#[cfg(test)]
555→mod tests {
556→    #![allow(clippy::unwrap_used)]
557→
558→    use super::*;
559→
560→    #[test]
561→    fn default_config_has_system_run_cap() {
562→        let config = NodeConfig::default();
563→        assert!(config.caps.contains(&"system.run".to_string()));
564→        assert!(config.commands.contains(&"system.run".to_string()));
565→    }
566→
567→    #[test]
568→    fn default_config_platform_is_current_os() {
569→        let config = NodeConfig::default();
570→        assert_eq!(config.platform, std::env::consts::OS);
571→    }
572→
573→    #[tokio::test]
574→    async fn system_which_finds_sh() {
575→        let config = NodeConfig::default();
576→        let host = NodeHost::new(config);
577→        let args = serde_json::json!({ "binary": "sh" });
578→        let result = host.handle_system_which(&args).await.unwrap();
579→        assert_eq!(result["found"], true);
580→        assert!(result["path"].as_str().unwrap().contains("sh"));
581→    }
582→
583→    #[tokio::test]
584→    async fn system_which_missing_binary() {
585→        let config = NodeConfig::default();
586→        let host = NodeHost::new(config);
587→        let args = serde_json::json!({ "binary": "definitely_not_a_real_binary_123456" });
588→        let result = host.handle_system_which(&args).await.unwrap();
589→        assert_eq!(result["found"], false);
590→    }
591→
592→    #[tokio::test]
593→    async fn system_run_echo() {
594→        let config = NodeConfig::default();
595→        let host = NodeHost::new(config);
596→        let args = serde_json::json!({
597→            "command": "echo hello",
598→            "timeout": 5000,
599→        });
600→        let result = host.handle_system_run(&args).await.unwrap();
601→        assert_eq!(result["stdout"].as_str().unwrap().trim(), "hello");
602→        assert_eq!(result["exitCode"], 0);
