  1→//! Install / manage a headless node as an OS service.
  2→//!
  3→//! - **macOS**: launchd user agent (`~/Library/LaunchAgents/org.moltis.node.plist`)
  4→//! - **Linux**: systemd user unit (`~/.config/systemd/user/moltis-node.service`)
  5→//!
  6→//! The service wraps `moltis node run` with the persisted connection parameters.
  7→
  8→use std::{
  9→    fs,
 10→    path::{Path, PathBuf},
 11→    process::Command,
 12→};
 13→
 14→use {
 15→    serde::{Deserialize, Serialize},
 16→    tracing::{debug, info},
 17→};
 18→
 19→// ── Persisted connection config ────────────────────────────────────────────
 20→
 21→/// Connection parameters saved to `~/.moltis/node.json` so the service can
 22→/// start without CLI flags.
 23→#[derive(Debug, Clone, Serialize, Deserialize)]
 24→pub struct ServiceConfig {
 25→    pub gateway_url: String,
 26→    pub device_token: String,
 27→    #[serde(skip_serializing_if = "Option::is_none")]
 28→    pub node_id: Option<String>,
 29→    #[serde(skip_serializing_if = "Option::is_none")]
 30→    pub display_name: Option<String>,
 31→    #[serde(skip_serializing_if = "Option::is_none")]
 32→    pub working_dir: Option<String>,
 33→    #[serde(default = "default_timeout")]
 34→    pub timeout: u64,
 35→}
 36→
 37→fn default_timeout() -> u64 {
 38→    300
 39→}
 40→
 41→impl ServiceConfig {
 42→    /// Load from `<data_dir>/node.json`.
 43→    pub fn load(data_dir: &Path) -> anyhow::Result<Self> {
 44→        let path = data_dir.join("node.json");
 45→        let contents = fs::read_to_string(&path)
 46→            .map_err(|e| anyhow::anyhow!("cannot read {}: {e}", path.display()))?;
 47→        let config: Self = serde_json::from_str(&contents)?;
 48→        Ok(config)
 49→    }
 50→
 51→    /// Save to `<data_dir>/node.json`.
 52→    pub fn save(&self, data_dir: &Path) -> anyhow::Result<()> {
 53→        fs::create_dir_all(data_dir)?;
 54→        let path = data_dir.join("node.json");
 55→        let json = serde_json::to_string_pretty(self)?;
 56→        fs::write(&path, json)?;
 57→        info!(path = %path.display(), "saved node config");
 58→        Ok(())
 59→    }
 60→}
 61→
 62→// ── Platform constants ─────────────────────────────────────────────────────
 63→
 64→/// macOS launchd label.
 65→const LAUNCHD_LABEL: &str = "org.moltis.node";
 66→
 67→/// systemd user unit name.
 68→const SYSTEMD_UNIT: &str = "moltis-node.service";
 69→
 70→// ── Service actions ────────────────────────────────────────────────────────
 71→
 72→/// Install the node as an OS service.
 73→///
 74→/// Saves the connection config, generates the service file, and enables it.
 75→pub fn install(data_dir: &Path, config: &ServiceConfig) -> anyhow::Result<()> {
 76→    config.save(data_dir)?;
 77→
 78→    let moltis_bin = resolve_binary()?;
 79→    let log_path = data_dir.join("node.log");
 80→
 81→    if cfg!(target_os = "macos") {
 82→        install_launchd(&moltis_bin, config, &log_path)
 83→    } else if cfg!(target_os = "linux") {
 84→        install_systemd(&moltis_bin, config, &log_path)
 85→    } else {
 86→        anyhow::bail!("service install not supported on {}", std::env::consts::OS)
 87→    }
 88→}
 89→
 90→/// Uninstall the service and remove generated files.
 91→pub fn uninstall(data_dir: &Path) -> anyhow::Result<()> {
 92→    if cfg!(target_os = "macos") {
 93→        uninstall_launchd()
 94→    } else if cfg!(target_os = "linux") {
 95→        uninstall_systemd()
 96→    } else {
 97→        anyhow::bail!(
 98→            "service uninstall not supported on {}",
 99→            std::env::consts::OS
100→        )
101→    }?;
102→
103→    // Remove persisted config.
104→    let config_path = data_dir.join("node.json");
105→    if config_path.exists() {
106→        fs::remove_file(&config_path)?;
107→        info!(path = %config_path.display(), "removed node config");
108→    }
109→
110→    Ok(())
111→}
112→
113→/// Print the service status.
114→pub fn status() -> anyhow::Result<ServiceStatus> {
115→    if cfg!(target_os = "macos") {
116→        status_launchd()
117→    } else if cfg!(target_os = "linux") {
118→        status_systemd()
119→    } else {
120→        anyhow::bail!("service status not supported on {}", std::env::consts::OS)
121→    }
122→}
123→
124→/// Stop the service.
125→pub fn stop() -> anyhow::Result<()> {
126→    if cfg!(target_os = "macos") {
127→        stop_launchd()
128→    } else if cfg!(target_os = "linux") {
129→        stop_systemd()
130→    } else {
131→        anyhow::bail!("service stop not supported on {}", std::env::consts::OS)
132→    }
133→}
134→
135→/// Restart the service.
136→pub fn restart() -> anyhow::Result<()> {
137→    if cfg!(target_os = "macos") {
138→        restart_launchd()
139→    } else if cfg!(target_os = "linux") {
140→        restart_systemd()
141→    } else {
142→        anyhow::bail!("service restart not supported on {}", std::env::consts::OS)
143→    }
144→}
145→
146→/// Print the service log path.
147→pub fn log_path(data_dir: &Path) -> PathBuf {
148→    data_dir.join("node.log")
149→}
150→
151→// ── Status type ────────────────────────────────────────────────────────────
152→
153→#[derive(Debug)]
154→pub enum ServiceStatus {
155→    Running { pid: Option<u32> },
156→    Stopped,
157→    NotInstalled,
158→    Unknown(String),
159→}
160→
161→impl std::fmt::Display for ServiceStatus {
162→    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
163→        match self {
164→            Self::Running { pid: Some(p) } => write!(f, "running (pid {p})"),
165→            Self::Running { pid: None } => write!(f, "running"),
166→            Self::Stopped => write!(f, "stopped"),
167→            Self::NotInstalled => write!(f, "not installed"),
168→            Self::Unknown(msg) => write!(f, "unknown: {msg}"),
169→        }
170→    }
171→}
172→
173→// ── Binary resolution ──────────────────────────────────────────────────────
174→
175→fn resolve_binary() -> anyhow::Result<PathBuf> {
176→    // Prefer the running binary if it looks right.
177→    if let Ok(exe) = std::env::current_exe() {
178→        let name = exe.file_name().unwrap_or_default().to_string_lossy();
179→        if name == "moltis" || name.starts_with("moltis-") {
180→            return Ok(exe);
181→        }
182→    }
183→
184→    // Fall back to PATH lookup.
185→    which::which("moltis").map_err(|_| {
186→        anyhow::anyhow!("cannot find 'moltis' binary; ensure it is installed and in PATH")
187→    })
188→}
189→
190→// ── macOS launchd ──────────────────────────────────────────────────────────
191→
192→fn launchd_plist_path() -> anyhow::Result<PathBuf> {
193→    let home = home_dir()?;
194→    Ok(home
195→        .join("Library")
196→        .join("LaunchAgents")
197→        .join(format!("{LAUNCHD_LABEL}.plist")))
198→}
199→
200→/// Escape special XML characters for safe interpolation into plist values.
201→fn xml_escape(s: &str) -> String {
202→    s.replace('&', "&amp;")
203→        .replace('<', "&lt;")
204→        .replace('>', "&gt;")
205→        .replace('"', "&quot;")
206→}
207→
208→/// Generate a launchd plist XML string.
209→pub fn generate_launchd_plist(
210→    moltis_bin: &Path,
211→    config: &ServiceConfig,
212→    log_path: &Path,
213→) -> String {
214→    let bin = xml_escape(&moltis_bin.display().to_string());
215→    let log = xml_escape(&log_path.display().to_string());
216→
217→    let mut args = vec![
218→        format!("    <string>{bin}</string>"),
219→        "    <string>node</string>".to_string(),
220→        "    <string>run</string>".to_string(),
221→        format!("    <string>--host</string>"),
222→        format!("    <string>{}</string>", xml_escape(&config.gateway_url)),
223→        format!("    <string>--token</string>"),
224→        format!("    <string>{}</string>", xml_escape(&config.device_token)),
225→        format!("    <string>--timeout</string>"),
226→        format!("    <string>{}</string>", config.timeout),
227→    ];
228→
229→    if let Some(ref id) = config.node_id {
230→        args.push("    <string>--node-id</string>".to_string());
231→        args.push(format!("    <string>{}</string>", xml_escape(id)));
232→    }
233→    if let Some(ref name) = config.display_name {
234→        args.push("    <string>--name</string>".to_string());
235→        args.push(format!("    <string>{}</string>", xml_escape(name)));
236→    }
237→    if let Some(ref dir) = config.working_dir {
238→        args.push("    <string>--working-dir</string>".to_string());
239→        args.push(format!("    <string>{}</string>", xml_escape(dir)));
240→    }
241→
242→    let args_str = args.join("\n");
243→
244→    format!(
245→        r#"<?xml version="1.0" encoding="UTF-8"?>
246→<!DOCTYPE plist PUBLIC "-//Apple//DTD PLIST 1.0//EN" "http://www.apple.com/DTDs/PropertyList-1.0.dtd">
247→<plist version="1.0">
248→<dict>
249→  <key>Label</key>
250→  <string>{LAUNCHD_LABEL}</string>
251→  <key>ProgramArguments</key>
252→  <array>
253→{args_str}
254→  </array>
255→  <key>RunAtLoad</key>
256→  <true/>
257→  <key>KeepAlive</key>
258→  <dict>
259→    <key>SuccessfulExit</key>
260→    <false/>
261→  </dict>
262→  <key>ThrottleInterval</key>
263→  <integer>10</integer>
264→  <key>StandardOutPath</key>
265→  <string>{log}</string>
266→  <key>StandardErrorPath</key>
267→  <string>{log}</string>
268→  <key>ProcessType</key>
269→  <string>Background</string>
270→</dict>
271→</plist>
272→"#
273→    )
274→}
275→
276→fn install_launchd(
277→    moltis_bin: &Path,
278→    config: &ServiceConfig,
279→    log_path: &Path,
280→) -> anyhow::Result<()> {
281→    let plist_path = launchd_plist_path()?;
282→
283→    // Unload first if already loaded (ignore errors).
284→    let _ = Command::new("launchctl")
285→        .args([
286→            "bootout",
287→            &format!("gui/{}", uid()),
288→            plist_path.to_str().unwrap_or_default(),
289→        ])
290→        .output();
291→
292→    let plist = generate_launchd_plist(moltis_bin, config, log_path);
293→
294→    if let Some(parent) = plist_path.parent() {
295→        fs::create_dir_all(parent)?;
296→    }
297→    fs::write(&plist_path, &plist)?;
298→    info!(path = %plist_path.display(), "wrote launchd plist");
299→
300→    let output = Command::new("launchctl")
301→        .args([
302→            "bootstrap",
303→            &format!("gui/{}", uid()),
304→            plist_path.to_str().unwrap_or_default(),
305→        ])
306→        .output()?;
307→
308→    if !output.status.success() {
309→        let stderr = String::from_utf8_lossy(&output.stderr);
310→        anyhow::bail!("launchctl bootstrap failed: {stderr}");
311→    }
312→
313→    info!("node service installed and started");
314→    Ok(())
315→}
316→
317→fn uninstall_launchd() -> anyhow::Result<()> {
318→    let plist_path = launchd_plist_path()?;
319→
320→    if !plist_path.exists() {
321→        anyhow::bail!("service not installed (plist not found)");
322→    }
323→
324→    let _ = Command::new("launchctl")
325→        .args([
326→            "bootout",
327→            &format!("gui/{}", uid()),
328→            plist_path.to_str().unwrap_or_default(),
329→        ])
330→        .output();
331→
332→    fs::remove_file(&plist_path)?;
333→    info!(path = %plist_path.display(), "removed launchd plist");
334→    info!("node service uninstalled");
335→    Ok(())
336→}
337→
338→fn status_launchd() -> anyhow::Result<ServiceStatus> {
339→    let plist_path = launchd_plist_path()?;
340→    if !plist_path.exists() {
341→        return Ok(ServiceStatus::NotInstalled);
342→    }
343→
344→    let output = Command::new("launchctl")
345→        .args(["print", &format!("gui/{}/{LAUNCHD_LABEL}", uid())])
346→        .output()?;
347→
348→    if !output.status.success() {
349→        return Ok(ServiceStatus::Stopped);
350→    }
351→
352→    let stdout = String::from_utf8_lossy(&output.stdout);
353→
354→    // Parse PID from `launchctl print` output: "pid = 12345"
355→    let pid = stdout.lines().find_map(|line| {
356→        let trimmed = line.trim();
357→        if trimmed.starts_with("pid = ") {
358→            trimmed.strip_prefix("pid = ")?.parse::<u32>().ok()
359→        } else {
360→            None
361→        }
362→    });
363→
364→    Ok(ServiceStatus::Running { pid })
365→}
366→
367→fn stop_launchd() -> anyhow::Result<()> {
368→    let plist_path = launchd_plist_path()?;
369→    if !plist_path.exists() {
370→        anyhow::bail!("service not installed");
371→    }
372→
373→    let output = Command::new("launchctl")
374→        .args(["kill", "SIGTERM", &format!("gui/{}/{LAUNCHD_LABEL}", uid())])
375→        .output()?;
376→
377→    if !output.status.success() {
378→        let stderr = String::from_utf8_lossy(&output.stderr);
379→        // "No such process" is fine — already stopped.
380→        if !stderr.contains("No such process") && !stderr.contains("3: No such process") {
381→            anyhow::bail!("launchctl kill failed: {stderr}");
382→        }
383→    }
384→
385→    info!("node service stopped");
386→    Ok(())
387→}
388→
389→fn restart_launchd() -> anyhow::Result<()> {
390→    let plist_path = launchd_plist_path()?;
391→    if !plist_path.exists() {
392→        anyhow::bail!("service not installed");
393→    }
394→
395→    // kickstart -k kills and restarts the service.
396→    let output = Command::new("launchctl")
397→        .args(["kickstart", "-k", &format!("gui/{}/{LAUNCHD_LABEL}", uid())])
398→        .output()?;
399→
400→    if !output.status.success() {
401→        let stderr = String::from_utf8_lossy(&output.stderr);
402→        anyhow::bail!("launchctl kickstart failed: {stderr}");
403→    }
404→
405→    info!("node service restarted");
406→    Ok(())
407→}
408→
409→// ── Linux systemd ──────────────────────────────────────────────────────────
410→
411→fn systemd_unit_path() -> anyhow::Result<PathBuf> {
412→    let home = home_dir()?;
413→    Ok(home
414→        .join(".config")
415→        .join("systemd")
416→        .join("user")
417→        .join(SYSTEMD_UNIT))
418→}
419→
420→/// Generate a systemd user unit file.
421→pub fn generate_systemd_unit(moltis_bin: &Path, config: &ServiceConfig, log_path: &Path) -> String {
422→    let bin = moltis_bin.display();
423→    let log = log_path.display();
424→
425→    let mut exec_args = format!(
426→        "{bin} node run --host \"{}\" --token \"{}\" --timeout {}",
427→        config.gateway_url.replace('"', "\\\""),
428→        config.device_token.replace('"', "\\\""),
429→        config.timeout,
430→    );
431→
432→    if let Some(ref id) = config.node_id {
433→        exec_args.push_str(&format!(" --node-id \"{}\"", id.replace('"', "\\\"")));
434→    }
435→    if let Some(ref name) = config.display_name {
436→        exec_args.push_str(&format!(" --name \"{}\"", name.replace('"', "\\\"")));
437→    }
438→    if let Some(ref dir) = config.working_dir {
439→        exec_args.push_str(&format!(" --working-dir \"{}\"", dir.replace('"', "\\\"")));
440→    }
441→
442→    format!(
443→        r#"[Unit]
444→Description=Moltis Node Host
445→After=network-online.target
446→Wants=network-online.target
447→
448→[Service]
449→Type=simple
450→ExecStart={exec_args}
451→Restart=on-failure
452→RestartSec=10
453→StandardOutput=append:{log}
454→StandardError=append:{log}
455→Environment=RUST_LOG=info
456→
457→[Install]
458→WantedBy=default.target
459→"#
460→    )
461→}
462→
463→fn install_systemd(
464→    moltis_bin: &Path,
465→    config: &ServiceConfig,
466→    log_path: &Path,
467→) -> anyhow::Result<()> {
468→    let unit_path = systemd_unit_path()?;
469→
470→    // Stop if already running (ignore errors).
471→    let _ = Command::new("systemctl")
472→        .args(["--user", "stop", SYSTEMD_UNIT])
473→        .output();
474→
475→    let unit = generate_systemd_unit(moltis_bin, config, log_path);
476→
477→    if let Some(parent) = unit_path.parent() {
478→        fs::create_dir_all(parent)?;
479→    }
480→    fs::write(&unit_path, &unit)?;
481→    info!(path = %unit_path.display(), "wrote systemd unit");
482→
483→    // Reload, enable, start.
484→    run_systemctl(&["daemon-reload"])?;
485→    run_systemctl(&["enable", SYSTEMD_UNIT])?;
486→    run_systemctl(&["start", SYSTEMD_UNIT])?;
487→
488→    info!("node service installed and started");
489→    Ok(())
490→}
491→
492→fn uninstall_systemd() -> anyhow::Result<()> {
493→    let unit_path = systemd_unit_path()?;
494→
495→    if !unit_path.exists() {
496→        anyhow::bail!("service not installed (unit file not found)");
497→    }
498→
499→    let _ = run_systemctl(&["stop", SYSTEMD_UNIT]);
500→    let _ = run_systemctl(&["disable", SYSTEMD_UNIT]);
501→
502→    fs::remove_file(&unit_path)?;
503→    let _ = run_systemctl(&["daemon-reload"]);
504→
505→    info!(path = %unit_path.display(), "removed systemd unit");
506→    info!("node service uninstalled");
507→    Ok(())
508→}
509→
510→fn status_systemd() -> anyhow::Result<ServiceStatus> {
511→    let unit_path = systemd_unit_path()?;
512→    if !unit_path.exists() {
513→        return Ok(ServiceStatus::NotInstalled);
514→    }
515→
516→    let output = Command::new("systemctl")
517→        .args(["--user", "is-active", SYSTEMD_UNIT])
518→        .output()?;
519→
520→    let state = String::from_utf8_lossy(&output.stdout).trim().to_string();
521→
522→    match state.as_str() {
523→        "active" => {
524→            // Get PID.
525→            let pid_output = Command::new("systemctl")
526→                .args([
527→                    "--user",
528→                    "show",
529→                    SYSTEMD_UNIT,
530→                    "--property=MainPID",
531→                    "--value",
532→                ])
533→                .output()?;
534→            let pid = String::from_utf8_lossy(&pid_output.stdout)
535→                .trim()
536→                .parse::<u32>()
537→                .ok()
538→                .filter(|p| *p > 0);
539→            Ok(ServiceStatus::Running { pid })
540→        },
541→        "inactive" | "deactivating" => Ok(ServiceStatus::Stopped),
542→        "failed" => Ok(ServiceStatus::Unknown("failed".into())),
543→        other => Ok(ServiceStatus::Unknown(other.into())),
544→    }
545→}
546→
547→fn stop_systemd() -> anyhow::Result<()> {
548→    let unit_path = systemd_unit_path()?;
549→    if !unit_path.exists() {
550→        anyhow::bail!("service not installed");
551→    }
552→    run_systemctl(&["stop", SYSTEMD_UNIT])?;
553→    info!("node service stopped");
554→    Ok(())
555→}
556→
557→fn restart_systemd() -> anyhow::Result<()> {
558→    let unit_path = systemd_unit_path()?;
559→    if !unit_path.exists() {
560→        anyhow::bail!("service not installed");
561→    }
562→    run_systemctl(&["restart", SYSTEMD_UNIT])?;
563→    info!("node service restarted");
564→    Ok(())
565→}
566→
567→fn run_systemctl(args: &[&str]) -> anyhow::Result<()> {
568→    let mut full_args = vec!["--user"];
569→    full_args.extend_from_slice(args);
570→
571→    debug!(args = ?full_args, "systemctl");
572→
573→    let output = Command::new("systemctl").args(&full_args).output()?;
574→    if !output.status.success() {
575→        let stderr = String::from_utf8_lossy(&output.stderr);
576→        anyhow::bail!("systemctl {} failed: {stderr}", args.join(" "));
577→    }
578→    Ok(())
579→}
