581→// ── Helpers ────────────────────────────────────────────────────────────────
582→
583→fn home_dir() -> anyhow::Result<PathBuf> {
584→    std::env::var_os("HOME")
585→        .map(PathBuf::from)
586→        .ok_or_else(|| anyhow::anyhow!("cannot determine home directory (HOME not set)"))
587→}
588→
589→fn uid() -> u32 {
590→    Command::new("id")
591→        .arg("-u")
592→        .output()
593→        .ok()
594→        .and_then(|o| String::from_utf8_lossy(&o.stdout).trim().parse().ok())
595→        .unwrap_or(501) // macOS default user uid
596→}
