221→// ── Gateway RPC helpers ────────────────────────────────────────────────────
222→
223→/// Call `device.token.create` on the gateway and print the token + command.
224→async fn cmd_generate_token(host: &str, api_key: Option<&str>, name: Option<&str>) -> Result<()> {
225→    let mut params = serde_json::Map::new();
226→    if let Some(n) = name {
227→        params.insert("displayName".into(), serde_json::json!(n));
228→    }
229→    params.insert("platform".into(), serde_json::json!("remote"));
230→
231→    let result = gateway_rpc(host, api_key, "device.token.create", params.into()).await?;
232→
233→    let token = result
234→        .get("deviceToken")
235→        .and_then(|v| v.as_str())
236→        .ok_or_else(|| anyhow::anyhow!("unexpected response: missing deviceToken"))?;
237→
238→    let ws_url = http_to_ws(host);
239→
240→    println!("Device token: {token}");
241→    println!();
242→    println!("Run this on the remote machine:");
243→    println!("  moltis node add --host {ws_url} --token {token}");
244→    println!();
245→    println!("The token is shown once and cannot be retrieved later.");
246→
247→    Ok(())
248→}
249→
250→/// Call `node.list` on the gateway and print connected nodes.
251→async fn cmd_list(host: &str, api_key: Option<&str>) -> Result<()> {
252→    let result = gateway_rpc(host, api_key, "node.list", serde_json::json!({})).await?;
253→
254→    let nodes = result
255→        .get("nodes")
256→        .and_then(|v| v.as_array())
257→        .cloned()
258→        .unwrap_or_default();
259→
260→    if nodes.is_empty() {
261→        println!("No nodes connected.");
262→        return Ok(());
263→    }
264→
265→    for node in &nodes {
266→        let id = node.get("nodeId").and_then(|v| v.as_str()).unwrap_or("?");
267→        let name = node
268→            .get("displayName")
269→            .and_then(|v| v.as_str())
270→            .unwrap_or("(unnamed)");
271→        let platform = node.get("platform").and_then(|v| v.as_str()).unwrap_or("?");
272→
273→        println!("{id}  {name}  ({platform})");
274→    }
275→
276→    Ok(())
277→}
