279→/// Send a single RPC request to the gateway over HTTP (JSON-RPC style).
280→///
281→/// The gateway exposes RPC methods over the WebSocket protocol, but for
282→/// one-shot CLI commands we use the `/api/rpc` endpoint when available,
283→/// falling back to a transient WebSocket connection.
284→async fn gateway_rpc(
285→    host: &str,
286→    api_key: Option<&str>,
287→    method: &str,
288→    params: serde_json::Value,
289→) -> Result<serde_json::Value> {
290→    let url = format!("{}/api/rpc", host.trim_end_matches('/'));
291→    let body = serde_json::json!({
292→        "method": method,
293→        "params": params,
294→    });
295→
296→    let client = reqwest::Client::new();
297→    let mut req = client.post(&url).json(&body);
298→    if let Some(key) = api_key {
299→        req = req.header("Authorization", format!("Bearer {key}"));
300→    }
301→
302→    let resp = req
303→        .send()
304→        .await
305→        .map_err(|e| anyhow::anyhow!("cannot reach gateway at {host}: {e}"))?;
306→
307→    if !resp.status().is_success() {
308→        let status = resp.status();
309→        let body = resp.text().await.unwrap_or_default();
310→        anyhow::bail!("gateway returned {status}: {body}");
311→    }
312→
313→    let result: serde_json::Value = resp.json().await?;
314→
315→    if let Some(err) = result.get("error") {
316→        let msg = err
317→            .get("message")
318→            .and_then(|v| v.as_str())
319→            .unwrap_or("unknown error");
320→        anyhow::bail!("RPC error: {msg}");
321→    }
322→
323→    Ok(result.get("payload").cloned().unwrap_or(result))
324→}
325→
326→/// Convert `http://host:port` to `ws://host:port/ws`.
327→fn http_to_ws(http_url: &str) -> String {
328→    let ws = http_url
329→        .replace("https://", "wss://")
330→        .replace("http://", "ws://");
331→    let base = ws.trim_end_matches('/');
332→    format!("{base}/ws")
333→}
