 18→/// The hostname used for loopback URLs instead of raw `127.0.0.1`.
 19→/// Subdomains of `.localhost` resolve to loopback per RFC 6761.
 20→pub const LOCALHOST_DOMAIN: &str = "moltis.localhost";
 21→
 22→/// Additional SAN entries that should be present on the auto-generated server
 23→/// certificate for this runtime.
 24→#[derive(Clone, Debug, Eq, Ord, PartialEq, PartialOrd)]
 25→pub enum ServerSan {
 26→    Dns(String),
 27→    Ip(IpAddr),
 28→}
 29→
 30→impl ServerSan {
 31→    fn metadata_line(&self) -> String {
 32→        match self {
 33→            Self::Dns(name) => format!("dns:{name}"),
 34→            Self::Ip(ip) => format!("ip:{ip}"),
 35→        }
 36→    }
 37→
 38→    fn from_metadata_line(line: &str) -> Option<Self> {
 39→        let (kind, value) = line.split_once(':')?;
 40→        match kind {
 41→            "dns" if !value.is_empty() => Some(Self::Dns(value.to_string())),
 42→            "ip" => value.parse().ok().map(Self::Ip),
 43→            _ => None,
 44→        }
 45→    }
 46→}
 47→
 48→/// DNS SAN names that must always exist on generated server certificates.
 49→fn required_dns_san_names() -> Vec<String> {
 50→    let mut names = vec![
 51→        LOCALHOST_DOMAIN.to_string(),
 52→        format!("*.{LOCALHOST_DOMAIN}"),
 53→        "localhost".to_string(),
 54→    ];
 55→
 56→    if let Some(hostname) = hostname::get()
 57→        .ok()
 58→        .and_then(|host| host.into_string().ok())
 59→    {
 60→        append_system_host_sans(&mut names, &hostname);
 61→    }
 62→
 63→    names.sort_unstable();
 64→    names.dedup();
 65→    names
 66→}
 67→
 68→fn append_system_host_sans(names: &mut Vec<String>, hostname: &str) {
 69→    let normalized = hostname.trim().trim_end_matches('.').to_ascii_lowercase();
 70→
 71→    if normalized.is_empty() || normalized == "localhost" || normalized == LOCALHOST_DOMAIN {
 72→        return;
 73→    }
 74→
 75→    names.push(normalized.clone());
 76→    if !normalized.contains('.') {
 77→        names.push(format!("{normalized}.local"));
 78→    }
 79→}
 80→
 81→fn default_required_sans() -> Vec<ServerSan> {
 82→    let mut sans = required_dns_san_names()
 83→        .into_iter()
 84→        .map(ServerSan::Dns)
 85→        .collect::<Vec<_>>();
 86→    sans.push(ServerSan::Ip(IpAddr::V4(std::net::Ipv4Addr::LOCALHOST)));
 87→    sans.push(ServerSan::Ip(IpAddr::V6(std::net::Ipv6Addr::LOCALHOST)));
 88→    normalize_sans(sans)
 89→}
 90→
 91→fn required_server_sans(runtime_sans: &[ServerSan]) -> Vec<ServerSan> {
 92→    normalize_sans(
 93→        default_required_sans()
 94→            .into_iter()
 95→            .chain(runtime_sans.iter().cloned()),
 96→    )
 97→}
 98→
 99→fn normalize_sans(sans: impl IntoIterator<Item = ServerSan>) -> Vec<ServerSan> {
100→    sans.into_iter()
101→        .collect::<BTreeSet<_>>()
102→        .into_iter()
103→        .collect()
104→}
105→
106→fn is_default_loopback_ip(ip: &IpAddr) -> bool {
107→    matches!(
108→        ip,
109→        IpAddr::V4(v4) if *v4 == std::net::Ipv4Addr::LOCALHOST
110→    ) || matches!(
111→        ip,
112→        IpAddr::V6(v6) if *v6 == std::net::Ipv6Addr::LOCALHOST
113→    )
114→}
115→
116→fn der_contains_ascii(der: &[u8], needle: &str) -> bool {
117→    der.windows(needle.len())
118→        .any(|window| window == needle.as_bytes())
119→}
