121→/// Trait for TLS certificate management, allowing alternative implementations.
122→pub trait CertManager: Send + Sync {
123→    /// Returns (ca_cert_path, server_cert_path, server_key_path).
124→    /// Generates certificates if they don't exist or are expired.
125→    fn ensure_certs(&self, runtime_sans: &[ServerSan]) -> Result<(PathBuf, PathBuf, PathBuf)>;
126→
127→    /// Build a `rustls::ServerConfig` from the given cert and key PEM files.
128→    fn build_rustls_config(&self, cert: &Path, key: &Path) -> Result<ServerConfig>;
129→}
130→
131→/// Default file-system-backed certificate manager.
132→pub struct FsCertManager {
133→    cert_dir: PathBuf,
134→}
135→
136→impl FsCertManager {
137→    pub fn new() -> Result<Self> {
138→        let dir = cert_dir()?;
139→        Ok(Self { cert_dir: dir })
140→    }
141→
142→    #[allow(clippy::unwrap_used, clippy::expect_used)]
143→    #[cfg(test)]
144→    pub fn with_dir(dir: PathBuf) -> Self {
145→        Self { cert_dir: dir }
146→    }
147→}
148→
149→/// Returns the certificate storage directory (`~/.config/moltis/certs/`).
150→pub fn cert_dir() -> Result<PathBuf> {
151→    let dir = moltis_config::config_dir()
152→        .unwrap_or_else(|| PathBuf::from(".moltis"))
153→        .join("certs");
154→    std::fs::create_dir_all(&dir).context("failed to create certs directory")?;
155→    Ok(dir)
156→}
157→
158→impl CertManager for FsCertManager {
159→    fn ensure_certs(&self, runtime_sans: &[ServerSan]) -> Result<(PathBuf, PathBuf, PathBuf)> {
160→        let ca_cert_path = self.cert_dir.join("ca.pem");
161→        let ca_key_path = self.cert_dir.join("ca-key.pem");
162→        let server_cert_path = self.cert_dir.join("server.pem");
163→        let server_key_path = self.cert_dir.join("server-key.pem");
164→        let server_sans_path = self.cert_dir.join("server-sans.txt");
165→        let required_sans = required_server_sans(runtime_sans);
166→
167→        let need_regen = !ca_cert_path.exists()
168→            || !server_cert_path.exists()
169→            || !server_key_path.exists()
170→            || is_expired(&server_cert_path, &server_sans_path, 30, &required_sans);
171→
172→        if need_regen {
173→            info!("generating TLS certificates");
174→            let (ca_cert_pem, ca_key_pem, server_cert_pem, server_key_pem) =
175→                generate_all(&required_sans)?;
176→            std::fs::write(&ca_cert_path, &ca_cert_pem)?;
177→            std::fs::write(&ca_key_path, &ca_key_pem)?;
178→            std::fs::write(&server_cert_path, &server_cert_pem)?;
179→            std::fs::write(&server_key_path, &server_key_pem)?;
180→            write_san_metadata(&server_sans_path, &required_sans)?;
181→            info!(dir = %self.cert_dir.display(), "certificates written");
182→        }
183→
184→        Ok((ca_cert_path, server_cert_path, server_key_path))
185→    }
186→
187→    fn build_rustls_config(&self, cert: &Path, key: &Path) -> Result<ServerConfig> {
188→        load_rustls_config(cert, key)
189→    }
190→}
191→
192→/// Check if a PEM cert file needs regeneration.
193→///
194→/// Returns `true` when the file is older than `days` days (proxy for
195→/// approaching expiry) **or** when it was generated before required DNS SANs
196→/// were added. The DER-encoded cert contains
197→/// DNS names as raw ASCII (IA5String), so a byte search on the decoded
198→/// DER is sufficient to detect the missing SAN.
199→fn is_expired(
200→    path: &Path,
201→    san_metadata_path: &Path,
202→    days: u64,
203→    required_sans: &[ServerSan],
204→) -> bool {
205→    let Ok(meta) = std::fs::metadata(path) else {
206→        return true;
207→    };
208→    let Ok(modified) = meta.modified() else {
209→        return true;
210→    };
211→    let age = SystemTime::now()
212→        .duration_since(modified)
213→        .unwrap_or_default();
214→    if age > time::Duration::days(days as i64).unsigned_abs() {
215→        return true;
216→    }
217→    needs_san_update(path, san_metadata_path, required_sans)
218→}
219→
220→/// Returns `true` if the cert at `path` does not contain the currently
221→/// required DNS SANs (i.e. was generated before the latest SAN migration).
222→fn needs_san_update(path: &Path, san_metadata_path: &Path, required_sans: &[ServerSan]) -> bool {
223→    if let Some(existing_sans) = read_san_metadata(san_metadata_path) {
224→        return required_sans
225→            .iter()
226→            .any(|entry| !existing_sans.contains(entry));
227→    }
228→
229→    let Ok(pem_bytes) = std::fs::read(path) else {
230→        return true;
231→    };
232→    let certs: Vec<_> = rustls_pemfile::certs(&mut BufReader::new(pem_bytes.as_slice()))
233→        .filter_map(|r| r.ok())
234→        .collect();
235→    if certs.is_empty() {
236→        return true;
237→    }
238→    let der = certs[0].as_ref();
239→    required_sans.iter().any(|entry| match entry {
240→        // Wildcard entries are not required for compatibility checks.
241→        ServerSan::Dns(name) if !name.starts_with("*.") => !der_contains_ascii(der, name),
242→        // Legacy certs do not carry SAN metadata, so require one regeneration
243→        // to pick up any non-loopback runtime IPs.
244→        ServerSan::Ip(ip) if !is_default_loopback_ip(ip) => true,
245→        _ => false,
246→    })
247→}
248→
249→fn read_san_metadata(path: &Path) -> Option<Vec<ServerSan>> {
250→    let contents = std::fs::read_to_string(path).ok()?;
251→    let mut sans = Vec::new();
252→    sans.extend(
253→        contents
254→            .lines()
255→            .map(str::trim)
256→            .filter(|line| !line.is_empty())
257→            .filter_map(ServerSan::from_metadata_line),
258→    );
259→    Some(normalize_sans(sans))
260→}
261→
262→fn write_san_metadata(path: &Path, sans: &[ServerSan]) -> Result<()> {
263→    let contents = sans
264→        .iter()
265→        .map(ServerSan::metadata_line)
266→        .collect::<Vec<_>>()
267→        .join("\n");
268→    let contents = if contents.is_empty() {
269→        String::new()
270→    } else {
271→        format!("{contents}\n")
272→    };
273→    std::fs::write(path, contents).context("write server SAN metadata")?;
274→    Ok(())
275→}
