277→/// Generate CA + server certificates. Returns (ca_cert, ca_key, server_cert, server_key) PEM strings.
278→fn generate_all(required_sans: &[ServerSan]) -> Result<(String, String, String, String)> {
279→    let now = OffsetDateTime::now_utc();
280→
281→    // --- CA ---
282→    let ca_key = KeyPair::generate()?;
283→    let mut ca_params = CertificateParams::new(Vec::<String>::new())?;
284→    ca_params
285→        .distinguished_name
286→        .push(DnType::CommonName, "Moltis Local CA");
287→    ca_params
288→        .distinguished_name
289→        .push(DnType::OrganizationName, "Moltis");
290→    ca_params.is_ca = IsCa::Ca(BasicConstraints::Unconstrained);
291→    ca_params.key_usages = vec![KeyUsagePurpose::KeyCertSign, KeyUsagePurpose::CrlSign];
292→    // 10-year validity from today.
293→    ca_params.not_before = now;
294→    ca_params.not_after = now + time::Duration::days(365 * 10);
295→    let ca_cert = ca_params.self_signed(&ca_key)?;
296→
297→    // --- Server cert signed by CA ---
298→    let server_key = KeyPair::generate()?;
299→    let mut server_params = CertificateParams::new(vec![LOCALHOST_DOMAIN.to_string()])?;
300→    server_params
301→        .distinguished_name
302→        .push(DnType::CommonName, LOCALHOST_DOMAIN);
303→    let subject_alt_names: Vec<SanType> = required_sans
304→        .iter()
305→        .filter_map(|entry| match entry {
306→            ServerSan::Dns(name) => name.as_str().try_into().ok().map(SanType::DnsName),
307→            ServerSan::Ip(ip) => Some(SanType::IpAddress(*ip)),
308→        })
309→        .collect();
310→    server_params.subject_alt_names = subject_alt_names;
311→    // 1-year validity from today.
312→    server_params.not_before = now;
313→    server_params.not_after = now + time::Duration::days(365);
314→    let server_cert = server_params.signed_by(&server_key, &ca_cert, &ca_key)?;
315→
316→    Ok((
317→        ca_cert.pem(),
318→        ca_key.serialize_pem(),
319→        server_cert.pem(),
320→        server_key.serialize_pem(),
321→    ))
322→}
323→
324→/// Load cert + key PEM files into a `rustls::ServerConfig`.
325→pub(crate) fn load_rustls_config(cert_path: &Path, key_path: &Path) -> Result<ServerConfig> {
326→    // Ensure a crypto provider is installed (ring via feature flag).
327→    let _ = rustls::crypto::ring::default_provider().install_default();
328→    let cert_file = std::fs::File::open(cert_path).context("open server cert")?;
329→    let key_file = std::fs::File::open(key_path).context("open server key")?;
330→
331→    let certs: Vec<_> = rustls_pemfile::certs(&mut BufReader::new(cert_file))
332→        .collect::<std::result::Result<Vec<_>, _>>()
333→        .context("parse certs")?;
334→
335→    let key = rustls_pemfile::private_key(&mut BufReader::new(key_file))
336→        .context("parse private key")?
337→        .context("no private key found")?;
338→
339→    let mut config = ServerConfig::builder()
340→        .with_no_client_auth()
341→        .with_single_cert(certs, key)
342→        .context("build rustls ServerConfig")?;
343→    config.alpn_protocols = vec![b"h2".to_vec(), b"http/1.1".to_vec()];
344→    Ok(config)
345→}
