  2→//!
  3→//! Reuses idle connections across consecutive `stream_with_tools_websocket`
  4→//! calls.  Connections are bucketed by `(ws_url, key_hash)` so different
  5→//! providers/keys never share a socket.  Stale entries are lazily evicted
  6→//! on checkout — no background reaper task.
  7→
  8→use std::{
  9→    collections::HashMap,
 10→    hash::{DefaultHasher, Hash, Hasher},
 11→    sync::LazyLock,
 12→};
 13→
 14→use {
 15→    tokio::{net::TcpStream, sync::Mutex},
 16→    tokio_tungstenite::{MaybeTlsStream, WebSocketStream},
 17→};
 18→
 19→use tracing::debug;
 20→
 21→// ── Pool constants (compile-time, not user-facing) ───────────────────
 22→
 23→const MAX_IDLE_PER_KEY: usize = 4;
 24→const MAX_IDLE_TOTAL: usize = 8;
 25→/// Must sit below OpenAI's 60 s server-side idle timeout.
 26→const IDLE_TIMEOUT: std::time::Duration = std::time::Duration::from_secs(55);
 27→/// Rotate connections periodically regardless of activity.
 28→const MAX_LIFETIME: std::time::Duration = std::time::Duration::from_secs(300);
 29→
 30→// ── Types ────────────────────────────────────────────────────────────
 31→
 32→/// Stream type returned by `tokio_tungstenite::connect_async`.
 33→pub type WsStream = WebSocketStream<MaybeTlsStream<TcpStream>>;
 34→
 35→/// Key used to bucket pooled connections.
 36→#[derive(Clone, Hash, Eq, PartialEq)]
 37→pub struct PoolKey {
 38→    ws_url: String,
 39→    key_hash: u64,
 40→}
 41→
 42→impl PoolKey {
 43→    /// Build a pool key from a WebSocket URL and an API key.
 44→    ///
 45→    /// The API key is hashed immediately — we never store the secret.
 46→    pub fn new(ws_url: &str, api_key: &secrecy::Secret<String>) -> Self {
 47→        use secrecy::ExposeSecret;
 48→        let mut hasher = DefaultHasher::new();
 49→        api_key.expose_secret().hash(&mut hasher);
 50→        Self {
 51→            ws_url: ws_url.to_string(),
 52→            key_hash: hasher.finish(),
 53→        }
 54→    }
 55→}
 56→
 57→struct IdleConnection {
 58→    stream: WsStream,
 59→    returned_at: std::time::Instant,
 60→    created_at: std::time::Instant,
 61→}
 62→
 63→/// A bounded pool of idle WebSocket connections.
 64→pub struct WsPool {
 65→    connections: Mutex<HashMap<PoolKey, Vec<IdleConnection>>>,
 66→}
 67→
 68→// ── Singleton ────────────────────────────────────────────────────────
 69→
 70→/// Global shared pool (mirrors `shared_http_client()` pattern).
 71→pub fn shared_ws_pool() -> &'static WsPool {
 72→    static POOL: LazyLock<WsPool> = LazyLock::new(WsPool::new);
 73→    &POOL
 74→}
 75→
 76→// ── Implementation ───────────────────────────────────────────────────
 77→
 78→impl WsPool {
 79→    fn new() -> Self {
 80→        Self {
 81→            connections: Mutex::new(HashMap::new()),
 82→        }
 83→    }
 84→
 85→    /// Try to reclaim an idle connection for the given key.
 86→    ///
 87→    /// Returns `None` when the pool has nothing valid.  Stale entries
 88→    /// (idle-timeout or max-lifetime) are dropped automatically.
 89→    pub async fn checkout(&self, key: &PoolKey) -> Option<(WsStream, std::time::Instant)> {
 90→        let mut map = self.connections.lock().await;
 91→        let bucket = map.get_mut(key)?;
 92→        let now = std::time::Instant::now();
 93→
 94→        while let Some(entry) = bucket.pop() {
 95→            if now.duration_since(entry.returned_at) > IDLE_TIMEOUT {
 96→                debug!("ws_pool: dropping idle-timeout connection");
 97→                continue;
 98→            }
 99→            if now.duration_since(entry.created_at) > MAX_LIFETIME {
100→                debug!("ws_pool: dropping max-lifetime connection");
101→                continue;
102→            }
103→            if bucket.is_empty() {
104→                map.remove(key);
105→            }
106→            debug!("ws_pool: reusing pooled connection");
107→            return Some((entry.stream, entry.created_at));
108→        }
109→
110→        // Bucket drained without finding a valid connection.
111→        map.remove(key);
112→        None
113→    }
114→
115→    /// Return a still-healthy connection for future reuse.
116→    ///
117→    /// The connection is silently dropped if it exceeds `MAX_LIFETIME`
118→    /// or the pool is already at capacity.
119→    pub async fn return_conn(
120→        &self,
121→        key: PoolKey,
122→        stream: WsStream,
123→        created_at: std::time::Instant,
124→    ) {
125→        let now = std::time::Instant::now();
126→        if now.duration_since(created_at) > MAX_LIFETIME {
127→            debug!("ws_pool: not returning max-lifetime connection");
128→            return;
129→        }
130→
131→        let mut map = self.connections.lock().await;
132→
133→        // Per-key cap — drop oldest if at limit.
134→        let bucket = map.entry(key.clone()).or_default();
135→        if bucket.len() >= MAX_IDLE_PER_KEY {
136→            debug!("ws_pool: per-key cap reached, dropping oldest");
137→            bucket.remove(0);
138→        }
139→        bucket.push(IdleConnection {
140→            stream,
141→            returned_at: now,
142→            created_at,
143→        });
144→
145→        // Global cap — evict oldest entry across all buckets.
146→        let total: usize = map.values().map(Vec::len).sum();
147→        if total > MAX_IDLE_TOTAL {
148→            debug!("ws_pool: global cap reached, evicting oldest");
149→            Self::evict_oldest(&mut map);
150→        }
151→    }
152→
153→    /// Remove the single oldest (by `returned_at`) entry across all buckets.
154→    fn evict_oldest(map: &mut HashMap<PoolKey, Vec<IdleConnection>>) {
155→        let mut oldest_key: Option<PoolKey> = None;
156→        let mut oldest_idx: usize = 0;
157→        let mut oldest_time: Option<std::time::Instant> = None;
158→
159→        for (key, bucket) in map.iter() {
160→            for (idx, entry) in bucket.iter().enumerate() {
161→                if oldest_time.is_none_or(|t| entry.returned_at < t) {
162→                    oldest_key = Some(key.clone());
163→                    oldest_idx = idx;
164→                    oldest_time = Some(entry.returned_at);
165→                }
166→            }
167→        }
168→
169→        if let Some(key) = oldest_key
170→            && let Some(bucket) = map.get_mut(&key)
171→        {
172→            bucket.remove(oldest_idx);
173→            if bucket.is_empty() {
174→                map.remove(&key);
175→            }
176→        }
177→    }
178→}
