  1→use {anyhow::Result, clap::Subcommand, std::time::Duration};
  2→
  3→/// `moltis node` subcommands — manage remote nodes.
  4→#[derive(Subcommand)]
  5→pub enum NodeAction {
  6→    /// Generate a device token so a remote machine can connect as a node.
  7→    ///
  8→    /// Prints the token and the `moltis node add` command to run on the
  9→    /// remote machine. This is the CLI equivalent of clicking "Generate Token"
 10→    /// on the web UI Nodes page.
 11→    GenerateToken {
 12→        /// Display name for the new device.
 13→        #[arg(long)]
 14→        name: Option<String>,
 15→        /// Gateway HTTP URL (used to call the RPC).
 16→        #[arg(long, default_value = "http://localhost:9090")]
 17→        host: String,
 18→        /// API key or password for authentication.
 19→        #[arg(long, env = "MOLTIS_API_KEY")]
 20→        api_key: Option<String>,
 21→    },
 22→
 23→    /// List all connected nodes.
 24→    List {
 25→        /// Gateway HTTP URL.
 26→        #[arg(long, default_value = "http://localhost:9090")]
 27→        host: String,
 28→        /// API key or password for authentication.
 29→        #[arg(long, env = "MOLTIS_API_KEY")]
 30→        api_key: Option<String>,
 31→    },
 32→
 33→    /// Join this machine to a gateway as a node.
 34→    ///
 35→    /// Saves the connection parameters and installs an OS service (launchd on
 36→    /// macOS, systemd on Linux) that starts on boot and reconnects on failure.
 37→    /// Pass --foreground to run in the current terminal instead.
 38→    Add {
 39→        /// Gateway WebSocket URL (e.g. ws://your-server:9090/ws).
 40→        #[arg(long, env = "MOLTIS_GATEWAY_URL")]
 41→        host: String,
 42→        /// Device token from `moltis node generate-token`.
 43→        #[arg(long, env = "MOLTIS_DEVICE_TOKEN")]
 44→        token: String,
 45→        /// Display name for this node.
 46→        #[arg(long)]
 47→        name: Option<String>,
 48→        /// Custom node ID (defaults to a random UUID).
 49→        #[arg(long)]
 50→        node_id: Option<String>,
 51→        /// Working directory for command execution.
 52→        #[arg(long)]
 53→        working_dir: Option<String>,
 54→        /// Maximum command timeout in seconds.
 55→        #[arg(long, default_value = "300")]
 56→        timeout: u64,
 57→        /// Run in the foreground instead of installing as a service.
 58→        #[arg(long)]
 59→        foreground: bool,
 60→    },
 61→
 62→    /// Run the node agent using saved config from `node.json`.
 63→    ///
 64→    /// This is the command invoked by the OS service (launchd / systemd).
 65→    /// It reads connection parameters from `~/.moltis/node.json`, which
 66→    /// is written by `moltis node add`.
 67→    Run {
 68→        /// Override the maximum command timeout in seconds.
 69→        #[arg(long)]
 70→        timeout: Option<u64>,
 71→    },
 72→
 73→    /// Disconnect this machine and remove the node service.
 74→    Remove,
 75→
 76→    /// Show the current node connection info and service status.
 77→    Status,
 78→
 79→    /// Print the path to the node log file.
 80→    Logs,
 81→}
 82→
 83→pub async fn handle_node(action: NodeAction) -> Result<()> {
 84→    match action {
 85→        NodeAction::GenerateToken {
 86→            name,
 87→            host,
 88→            api_key,
 89→        } => cmd_generate_token(&host, api_key.as_deref(), name.as_deref()).await,
 90→
 91→        NodeAction::List { host, api_key } => cmd_list(&host, api_key.as_deref()).await,
 92→
 93→        NodeAction::Add {
 94→            host,
 95→            token,
 96→            name,
 97→            node_id,
 98→            working_dir,
 99→            timeout,
100→            foreground,
101→        } => {
102→            let resolved_node_id = node_id.unwrap_or_else(|| uuid::Uuid::new_v4().to_string());
103→
104→            if foreground {
105→                let config = moltis_node_host::NodeConfig {
106→                    gateway_url: host,
107→                    device_token: token,
108→                    node_id: resolved_node_id,
109→                    display_name: name,
110→                    platform: std::env::consts::OS.into(),
111→                    caps: vec![
112→                        "system.run".into(),
113→                        "system.which".into(),
114→                        "system.providers".into(),
115→                    ],
116→                    commands: vec![
117→                        "system.run".into(),
118→                        "system.which".into(),
119→                        "system.providers".into(),
120→                    ],
121→                    exec_timeout: Duration::from_secs(timeout),
122→                    working_dir,
123→                };
124→
125→                let node = moltis_node_host::NodeHost::new(config);
126→                node.run().await
127→            } else {
128→                let data_dir = moltis_config::data_dir();
129→                let svc_config = moltis_node_host::ServiceConfig {
130→                    gateway_url: host,
131→                    device_token: token,
132→                    node_id: Some(resolved_node_id),
133→                    display_name: name,
134→                    working_dir,
135→                    timeout,
136→                };
137→
138→                moltis_node_host::service::install(&data_dir, &svc_config)?;
139→                println!("Node registered and service started.");
140→                println!(
141→                    "Logs: {}",
142→                    moltis_node_host::service::log_path(&data_dir).display()
143→                );
144→                Ok(())
145→            }
146→        },
147→
148→        NodeAction::Run { timeout } => {
149→            let data_dir = moltis_config::data_dir();
150→            let config = moltis_node_host::ServiceConfig::load(&data_dir)
151→                .map_err(|e| anyhow::anyhow!(
152→                    "cannot load node config: {e}\nRun `moltis node add` first to register this machine."
153→                ))?;
154→
155→            let exec_timeout = Duration::from_secs(timeout.unwrap_or(config.timeout));
156→
157→            let node_config = moltis_node_host::NodeConfig {
158→                gateway_url: config.gateway_url,
159→                device_token: config.device_token,
160→                node_id: config
161→                    .node_id
162→                    .unwrap_or_else(|| uuid::Uuid::new_v4().to_string()),
163→                display_name: config.display_name,
164→                platform: std::env::consts::OS.into(),
165→                caps: vec![
166→                    "system.run".into(),
167→                    "system.which".into(),
168→                    "system.providers".into(),
169→                ],
170→                commands: vec![
171→                    "system.run".into(),
172→                    "system.which".into(),
173→                    "system.providers".into(),
174→                ],
175→                exec_timeout,
176→                working_dir: config.working_dir,
177→            };
178→
179→            let node = moltis_node_host::NodeHost::new(node_config);
180→            node.run().await
181→        },
182→
183→        NodeAction::Remove => {
184→            let data_dir = moltis_config::data_dir();
185→            moltis_node_host::service::uninstall(&data_dir)?;
186→            println!("Node removed.");
187→            Ok(())
188→        },
189→
190→        NodeAction::Status => {
191→            let data_dir = moltis_config::data_dir();
192→            let config_path = data_dir.join("node.json");
193→
194→            if !config_path.exists() {
195→                println!("Not registered as a node.");
196→                return Ok(());
197→            }
198→
199→            let config = moltis_node_host::ServiceConfig::load(&data_dir)?;
200→            let status = moltis_node_host::service::status()?;
201→
202→            println!("Gateway: {}", config.gateway_url);
203→            if let Some(ref name) = config.display_name {
204→                println!("Name:    {name}");
205→            }
206→            println!("Service: {status}");
207→            Ok(())
208→        },
209→
210→        NodeAction::Logs => {
211→            let data_dir = moltis_config::data_dir();
212→            println!(
213→                "{}",
214→                moltis_node_host::service::log_path(&data_dir).display()
215→            );
216→            Ok(())
217→        },
218→    }
219→}
