221→// ── Gateway RPC helpers ────────────────────────────────────────────────────
222→
223→/// Call `device.token.create` on the gateway and print the token + command.
224→async fn cmd_generate_token(host: &str, api_key: Option<&str>, name: Option<&str>) -> Result<()> {
225→    let mut params = serde_json::Map::new();
226→    if let Some(n) = name {
227→        params.insert("displayName".into(), serde_json::json!(n));
228→    }
229→    params.insert("platform".into(), serde_json::json!("remote"));
230→
231→    let result = gateway_rpc(host, api_key, "device.token.create", params.into()).await?;
232→
233→    let token = result
